const Hero = () => {
  const [isMounted, setIsMounted] = useState(false);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    if (prefersReducedMotion) {
      return;
    }

    const timeout = setTimeout(() => setIsMounted(true), navDelay);
    return () => clearTimeout(timeout);
  }, []);

  const one = <h1>Hi, my name is</h1>;
  const two = <h2 className="big-heading hero-name">Thomas Doan.</h2>;
  const three = <h3 className="big-heading hero-title">I build things for the web.</h3>;
  const four = (
    <>
      <p>
        I am a senior full-stack engineer focused on product quality, performance, and thoughtful user
        experiences. I am currently open to new opportunities where I can help teams ship meaningful outcomes.
      </p>
    </>
  );
  const five = (
    <div className="cta-group">
      <a
        className="email-link"
        href="/resume.pdf"
        target="_blank"
        rel="noopener noreferrer"
        onClick={() =>
          trackEvent({
            category: 'cta',
            action: 'click_view_resume_hero',
            label: 'Hero View Resume',
          })
        }>
        View Resume
      </a>
      <a
        className="cta-secondary"
        href="/#contact"
        onClick={() =>
          trackEvent({
            category: 'cta',
            action: 'click_contact_me_hero',
            label: 'Hero Contact Me',
          })
        }>
        Contact Me
      </a>
    </div>
  );

  const items = [one, two, three, four, five];

  return (
    <StyledHeroSection>
      <div className="hero-inner">
        <div className="hero-copy">
          {prefersReducedMotion ? (
            <>
              {items.map((item, i) => (
                <div key={i}>{item}</div>
              ))}
            </>
          ) : (
            <TransitionGroup component={null}>
              {isMounted &&
                items.map((item, i) => (
                  <CSSTransition key={i} classNames="fadeup" timeout={loaderDelay}>
                    <div style={{ transitionDelay: `${i + 1}00ms` }}>{item}</div>
                  </CSSTransition>
                ))}
            </TransitionGroup>
          )}
        </div>

        <aside className="hero-panel" aria-label="Professional highlights">
          <div className="panel-header">
            <h4 className="panel-title">Product-minded engineering leadership</h4>
            <span className="panel-badge">Open to work</span>
          </div>

          <div className="panel-grid">
            <div className="panel-card">
              <p className="panel-kpi">5+</p>
              <p className="panel-label">Startups supported</p>
            </div>
            <div className="panel-card">
              <p className="panel-kpi">3</p>
              <p className="panel-label">Recent product teams</p>
            </div>
            <div className="panel-card">
              <p className="panel-kpi">Full-stack</p>
              <p className="panel-label">Frontend + backend delivery</p>
            </div>
            <div className="panel-card">
              <p className="panel-kpi">User-first</p>
              <p className="panel-label">Design + UX-aligned mindset</p>
            </div>
          </div>

          <p className="panel-note">
            I help teams ship polished products faster by combining strong engineering execution with clear
            product thinking.
          </p>
        </aside>
      </div>

      <div className="hero-proof" aria-label="Professional proof points">
        <p className="proof-head">Trusted by product-led startup teams</p>
        <div className="proof-grid">
          <div className="proof-item">
            <p className="proof-value">5+</p>
            <p className="proof-label">Startups across health + SaaS</p>
          </div>
          <div className="proof-item">
            <p className="proof-value">0→1</p>
            <p className="proof-label">Product launches and GTM support</p>
          </div>
          <div className="proof-item">
            <p className="proof-value">Full-stack</p>
            <p className="proof-label">Frontend, backend, and architecture</p>
          </div>
          <div className="proof-item">
            <p className="proof-value">UX-first</p>
            <p className="proof-label">Business outcomes with better UX</p>
          </div>
        </div>
      </div>
    </StyledHeroSection>
  );
};

export default Hero;
